namespace sv_5aa5e13677c240eabea0b6b9f4661422.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service holding per-circuit theme state.
/// Interactive components subscribe to OnChange to re-render when values change.
/// </summary>
public class ThemeState
{
    private Theme _currentTheme = Theme.Light;
    private string _accentColor = "#0d6efd";

    public Theme CurrentTheme
    {
        get => _currentTheme;
        set
        {
            if (_currentTheme == value) return;
            _currentTheme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChange;

    /// <summary>
    /// Apply multiple changes and fire a single notification.
    /// </summary>
    public void Update(Theme theme, string accentColor)
    {
        _currentTheme = theme;
        _accentColor = accentColor;
        NotifyChanged();
    }

    private void NotifyChanged() => OnChange?.Invoke();
}

@rendermode InteractiveServer
@inject sv_5aa5e13677c240eabea0b6b9f4661422.Services.ThemeState ThemeState
@implements IDisposable

<span class="theme-indicator" title="Current theme" style="color: @ThemeState.AccentColor;">
    @GetThemeIcon() @ThemeState.CurrentTheme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeState.OnChange += StateHasChanged;
    }

    private string GetThemeIcon() => ThemeState.CurrentTheme switch
    {
        sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme.Dark => "🌙",
        sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme.System => "💻",
        _ => "☀️"
    };

    public void Dispose()
    {
        ThemeState.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@inject sv_5aa5e13677c240eabea0b6b9f4661422.Services.ThemeState ThemeState
@implements IDisposable

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme" title="Toggle theme">
    @GetThemeIcon()
</button>

@code {
    protected override void OnInitialized()
    {
        ThemeState.OnChange += StateHasChanged;
    }

    private void CycleTheme()
    {
        ThemeState.CurrentTheme = ThemeState.CurrentTheme switch
        {
            sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme.Light => sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme.Dark,
            sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme.Dark => sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme.System,
            _ => sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme.Light
        };
    }

    private string GetThemeIcon() => ThemeState.CurrentTheme switch
    {
        sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme.Dark => "🌙",
        sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme.System => "💻",
        _ => "☀️"
    };

    public void Dispose()
    {
        ThemeState.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject sv_5aa5e13677c240eabea0b6b9f4661422.Services.ThemeState ThemeState
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@ThemeState.CurrentTheme" @onchange="OnThemeChanged">
                @foreach (var theme in Enum.GetValues<sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme>())
                {
                    <option value="@theme">@theme</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@ThemeState.AccentColor" @onchange="OnAccentChanged" />
                <span>@ThemeState.AccentColor</span>
            </div>
        </div>

        <div class="mt-4 p-3 rounded" style="background-color: @ThemeState.AccentColor; color: white;">
            Preview: @ThemeState.CurrentTheme mode with accent @ThemeState.AccentColor
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeState.OnChange += StateHasChanged;
    }

    private void OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<sv_5aa5e13677c240eabea0b6b9f4661422.Services.Theme>(
                e.Value?.ToString(), out var theme))
        {
            ThemeState.CurrentTheme = theme;
        }
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeState.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    public void Dispose()
    {
        ThemeState.OnChange -= StateHasChanged;
    }
}

